register_guarded_histogram_vec_with_registry!(
                histogram_opts!(
                    "iceberg_source_delete_files_per_data_file",
                    "Number of delete files attached per data file scan task",
                    // 1, 2, 4, 8, 16, 32, 64, 128
                    exponential_buckets(1.0, 2.0, 8).unwrap()
                ),
                &["source_id", "source_name", "table_name"],
                registry
            ).unwrap

async move {
            let reader = ParquetMetaDataReader::new();
            let size = self.meta.size;
            let meta = reader.load_and_finish(self, size).await?;

            Ok(Arc::new(meta))
        }.boxed

rw_columns
                .iter()
                .filter_map(|column| {
                    let exact_pos = root_column_names
                        .iter()
                        .position(|&name| name == column.name);
                    let pos = match (case_insensitive, exact_pos) {
                        (_, Some(pos)) => Some(pos),
                        (true, None) => lowercase_name_to_index
                            .get(&column.name.to_ascii_lowercase())
                            .copied()
                            .flatten(),
                        _ => None,
                    }?;
                    let arrow_field = converted_arrow_schema.fields.get(pos)?;
                    let arrow_data_type = arrow_field.data_type();
                    let rw_data_type: &risingwave_common::types::DataType = &column.data_type;
                    if is_parquet_schema_match_source_schema(arrow_data_type, rw_data_type) {
                        Some(pos)
                    } else {
                        None
                    }
                }).collect

converted_arrow_schema
            .fields
            .iter()
            .enumerate()
            .map(|(index, field_ref)| {
                let data_type = IcebergArrowConvert.type_from_field(field_ref).unwrap();
                let column_desc = ColumnDesc::named(
                    field_ref.name().clone(),
                    ColumnId::new(index as i32),
                    data_type,
                );
                SourceColumnDesc::from(&column_desc)
            }).collect

topic_partitions
            .iter()
            .map(|partition| {
                let (low, high) = watermarks.remove(partition).unwrap();
                let start_offset = {
                    let earliest_offset = low - 1;
                    let start = expect_start_offset
                        .as_mut()
                        .map(|m| m.remove(partition).flatten().unwrap_or(earliest_offset))
                        .unwrap_or(earliest_offset);
                    i64::max(start, earliest_offset)
                };
                let stop_offset = {
                    let stop = expect_stop_offset
                        .as_mut()
                        .map(|m| m.remove(partition).unwrap_or(Some(high)))
                        .unwrap_or(Some(high))
                        .unwrap_or(high);
                    i64::min(stop, high)
                };

                if start_offset > stop_offset {
                    tracing::warn!(
                        "Skipping topic {} partition {}: requested start offset {} is greater than stop offset {}",
                        self.topic,
                        partition,
                        start_offset,
                        stop_offset
                    );
                }
                KafkaSplit {
                    topic: self.topic.clone(),
                    partition: *partition,
                    start_offset: Some(start_offset),
                    stop_offset: Some(stop_offset),
                }
            })
            .collect::<Vec<KafkaSplit>>

addr_map
                    .into_iter()
                    .map(|(old_addr, new_addr)| {
                        let old_addr = HostAddr::from_str(&old_addr)?;
                        let new_addr = HostAddr::from_str(&new_addr)?;
                        let old_addr = BrokerAddr {
                            host: old_addr.host,
                            port: old_addr.port.to_string(),
                        };
                        let new_addr = BrokerAddr {
                            host: new_addr.host,
                            port: new_addr.port.to_string(),
                        };
                        Ok((old_addr, new_addr))
                    }).collect

endpoint
            .as_array()
            .unwrap()
            .iter()
